import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.BKDXG6j6.js";const p=JSON.parse('{"title":"Dealing with Legacy Code & Refactoring","description":"","frontmatter":{},"headers":[],"relativePath":"real-world/legacy-code.md","filePath":"real-world/legacy-code.md","lastUpdated":null}'),r={name:"real-world/legacy-code.md"};function n(l,e,s,c,d,g){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="dealing-with-legacy-code-refactoring" tabindex="-1">Dealing with Legacy Code &amp; Refactoring <a class="header-anchor" href="#dealing-with-legacy-code-refactoring" aria-label="Permalink to &quot;Dealing with Legacy Code &amp; Refactoring&quot;">​</a></h1><p>Taking over a massive, poorly-architected Android codebase (e.g., God Activities, giant nested callbacks, 10-year-old Java files) requires a surgically precise approach.</p><h2 id="_1-the-strangler-fig-pattern" tabindex="-1">1. The Strangler Fig Pattern <a class="header-anchor" href="#_1-the-strangler-fig-pattern" aria-label="Permalink to &quot;1. The Strangler Fig Pattern&quot;">​</a></h2><p>You cannot stop product development for 6 months to rewrite an app from scratch. You must rewrite it piecemeal while new features are continuously deployed.</p><p><strong>How it works:</strong></p><ol><li>Pick one specific screen or feature (e.g., the User Profile screen).</li><li>Rewrite that specific completely detached flow into modern Kotlin/Compose/MVVM.</li><li>Reroute the legacy app&#39;s navigation to point to your new Kotlin implementation instead of the old Java Activity.</li><li>Delete the old Java Activity.</li><li>Repeat for the next screen until the legacy code &quot;dies&quot; organically.</li></ol><h2 id="_2-writing-characterization-tests" tabindex="-1">2. Writing Characterization Tests <a class="header-anchor" href="#_2-writing-characterization-tests" aria-label="Permalink to &quot;2. Writing Characterization Tests&quot;">​</a></h2><p>Before modifying a highly complex Java &quot;God&quot; class because you want to extract logic, you must prove you didn&#39;t break anything.</p><ul><li>Write JUnit tests that document exactly what the class does <em>right now</em> with all its flaws.</li><li>Refactor the code.</li><li>If the tests still pass, you successfully extracted the logic cleanly.</li></ul><h2 id="_3-isolating-the-domain" tabindex="-1">3. Isolating the Domain <a class="header-anchor" href="#_3-isolating-the-domain" aria-label="Permalink to &quot;3. Isolating the Domain&quot;">​</a></h2><p>Legacy Android code often mixes networking, database queries, and UI manipulation in a single <code>onPostExecute()</code> block.</p><p><strong>Step 1:</strong> Create an interface for the operation (e.g., <code>interface UserRepository</code>). <strong>Step 2:</strong> Extract the nasty raw SQLite/Network code into the <code>UserRepositoryImpl</code>. <strong>Step 3:</strong> Inject the <code>UserRepository</code> into the legacy God Activity. Suddenly, the Activity is much smaller and testable, and you&#39;ve initiated Clean Architecture without breaking the app.</p><h2 id="_4-defending-against-regressions" tabindex="-1">4. Defending Against Regressions <a class="header-anchor" href="#_4-defending-against-regressions" aria-label="Permalink to &quot;4. Defending Against Regressions&quot;">​</a></h2><ul><li>Integrate <strong>ktlint/detekt</strong> immediately. Ensure all <em>new</em> code adheres strictly to high-quality standards.</li><li>Add <strong>Strict Mode</strong> in debug builds so developers are instantly aware if they accidentally push disk reads onto the main thread while refactoring asynchronous code.</li><li>Implement <strong>Baseline Profiles</strong> if the legacy application is sluggish at startup due to enormous XML View inflation.</li></ul>',14)])])}const u=t(r,[["render",n]]);export{p as __pageData,u as default};
